"use client";

import { useState, useRef, useEffect } from "react";
import { useTranslations } from "next-intl";
import { Plus, Type, Table, ListChecks, DollarSign, ListOrdered, StickyNote } from "lucide-react";
import { Button } from "@/shared/components/ui/Button";
import { BLOCK_REGISTRY, type BlockType, type QuoteBlock } from "../../types";

const ICON_MAP = {
  Type,
  Table,
  ListChecks,
  DollarSign,
  ListOrdered,
  StickyNote,
} as const;

interface AddBlockMenuProps {
  existingBlocks: QuoteBlock[];
  onAdd: (type: BlockType) => void;
}

export function AddBlockMenu({ existingBlocks, onAdd }: AddBlockMenuProps) {
  const t = useTranslations("Admin");
  const [open, setOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    if (open) document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [open]);

  const blockTypes = Object.entries(BLOCK_REGISTRY) as [BlockType, (typeof BLOCK_REGISTRY)[BlockType]][];

  return (
    <div className="relative" ref={menuRef}>
      <Button
        type="button"
        variant="secondary"
        size="md"
        onClick={() => setOpen(!open)}
        className="w-full border-dashed"
      >
        <Plus size={16} />
        {t("addBlock")}
      </Button>

      {open && (
        <div className="absolute z-20 mt-2 w-full bg-pragma-surface border border-pragma-border rounded-xl shadow-lg overflow-hidden">
          {blockTypes.map(([type, config]) => {
            const Icon = ICON_MAP[config.icon as keyof typeof ICON_MAP];
            const alreadyExists = existingBlocks.some((b) => b.type === type);
            const disabled = !config.allowMultiple && alreadyExists;

            return (
              <button
                key={type}
                type="button"
                disabled={disabled}
                onClick={() => {
                  onAdd(type);
                  setOpen(false);
                }}
                className="w-full flex items-center gap-3 px-4 py-3 text-sm text-left hover:bg-pragma-accent/10 transition-colors disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer"
              >
                <Icon size={16} className="text-pragma-accent shrink-0" />
                <span>{t(config.labelKey)}</span>
                {disabled && (
                  <span className="ml-auto text-xs text-pragma-muted">(max 1)</span>
                )}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { Card } from "@/shared/components/ui/Card";
import { ChevronUp, ChevronDown, X, Type, Table, ListChecks, DollarSign, ListOrdered, StickyNote } from "lucide-react";
import { BLOCK_REGISTRY, type QuoteBlock } from "../../types";
import { TextBlockEditor } from "./TextBlockEditor";
import { LineItemsBlockEditor } from "./LineItemsBlockEditor";
import { DeliverablesBlockEditor } from "./DeliverablesBlockEditor";
import { PricingBlockEditor } from "./PricingBlockEditor";
import { NextStepsBlockEditor } from "./NextStepsBlockEditor";
import { NotesBlockEditor } from "./NotesBlockEditor";
import type { Currency } from "../../types";

const ICON_MAP = {
  Type,
  Table,
  ListChecks,
  DollarSign,
  ListOrdered,
  StickyNote,
} as const;

interface BlockEditorProps {
  block: QuoteBlock;
  currency: Currency;
  locale: string;
  isFirst: boolean;
  isLast: boolean;
  onUpdate: (block: QuoteBlock) => void;
  onMoveUp: () => void;
  onMoveDown: () => void;
  onRemove: () => void;
}

export function BlockEditor({
  block,
  currency,
  locale,
  isFirst,
  isLast,
  onUpdate,
  onMoveUp,
  onMoveDown,
  onRemove,
}: BlockEditorProps) {
  const t = useTranslations("Admin");
  const config = BLOCK_REGISTRY[block.type];
  const Icon = ICON_MAP[config.icon as keyof typeof ICON_MAP];

  function renderEditor() {
    switch (block.type) {
      case "text":
        return <TextBlockEditor block={block} onUpdate={onUpdate} />;
      case "line-items":
        return <LineItemsBlockEditor block={block} currency={currency} locale={locale} onUpdate={onUpdate} />;
      case "deliverables":
        return <DeliverablesBlockEditor block={block} onUpdate={onUpdate} />;
      case "pricing":
        return <PricingBlockEditor block={block} onUpdate={onUpdate} />;
      case "next-steps":
        return <NextStepsBlockEditor block={block} onUpdate={onUpdate} />;
      case "notes":
        return <NotesBlockEditor block={block} onUpdate={onUpdate} />;
    }
  }

  return (
    <Card>
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <Icon size={16} className="text-pragma-accent" />
          <h3 className="text-sm font-semibold text-pragma-muted uppercase tracking-wider">
            {t(config.labelKey)}
          </h3>
        </div>
        <div className="flex items-center gap-1">
          <button
            type="button"
            onClick={onMoveUp}
            disabled={isFirst}
            className="p-1 text-pragma-muted hover:text-pragma-text disabled:opacity-30 transition-colors cursor-pointer disabled:cursor-not-allowed"
            title={t("moveUp")}
          >
            <ChevronUp size={16} />
          </button>
          <button
            type="button"
            onClick={onMoveDown}
            disabled={isLast}
            className="p-1 text-pragma-muted hover:text-pragma-text disabled:opacity-30 transition-colors cursor-pointer disabled:cursor-not-allowed"
            title={t("moveDown")}
          >
            <ChevronDown size={16} />
          </button>
          <button
            type="button"
            onClick={onRemove}
            className="p-1 text-pragma-muted hover:text-red-400 transition-colors cursor-pointer"
            title={t("removeBlock")}
          >
            <X size={16} />
          </button>
        </div>
      </div>
      {renderEditor()}
    </Card>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { Input } from "@/shared/components/ui/Input";
import { Textarea } from "@/shared/components/ui/Textarea";
import type { TextBlock, QuoteBlock } from "../../types";

interface Props {
  block: TextBlock;
  onUpdate: (block: QuoteBlock) => void;
}

export function TextBlockEditor({ block, onUpdate }: Props) {
  const t = useTranslations("Admin");

  return (
    <div className="space-y-3">
      <Input
        id={`${block.blockId}-heading`}
        label={t("sectionHeading")}
        value={block.data.heading}
        onChange={(e) =>
          onUpdate({ ...block, data: { ...block.data, heading: e.target.value } })
        }
        placeholder="e.g. The Problem, Opportunity, Scope..."
      />
      <Textarea
        id={`${block.blockId}-body`}
        label=""
        value={block.data.body}
        onChange={(e) =>
          onUpdate({ ...block, data: { ...block.data, body: e.target.value } })
        }
        placeholder="Write your content..."
      />
    </div>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { Button } from "@/shared/components/ui/Button";
import { Input } from "@/shared/components/ui/Input";
import { Plus, X } from "lucide-react";
import { nanoid } from "nanoid";
import type { LineItemsBlock, QuoteBlock, LineItem, Currency } from "../../types";
import {
  formatCurrency,
  calculateLineItemTotal,
  calculateSubtotal,
  calculateTotal,
} from "../../types";

interface Props {
  block: LineItemsBlock;
  currency: Currency;
  locale: string;
  onUpdate: (block: QuoteBlock) => void;
}

export function LineItemsBlockEditor({ block, currency, locale, onUpdate }: Props) {
  const t = useTranslations("Admin");
  const { items, discount, heading } = block.data;

  function updateData(patch: Partial<LineItemsBlock["data"]>) {
    onUpdate({ ...block, data: { ...block.data, ...patch } });
  }

  function updateItem(id: string, field: keyof LineItem, value: string | number) {
    updateData({
      items: items.map((item) =>
        item.id === id ? { ...item, [field]: value } : item
      ),
    });
  }

  function addItem() {
    updateData({
      items: [...items, { id: nanoid(6), description: "", quantity: 1, unitPrice: 0 }],
    });
  }

  function removeItem(id: string) {
    updateData({ items: items.filter((item) => item.id !== id) });
  }

  const subtotal = calculateSubtotal(items);
  const total = calculateTotal(items, discount);

  return (
    <div className="space-y-3">
      <Input
        id={`${block.blockId}-heading`}
        label={t("groupName")}
        value={heading}
        onChange={(e) => updateData({ heading: e.target.value })}
        placeholder="e.g. Development, Design..."
      />

      <div className="hidden sm:grid grid-cols-12 gap-3 text-xs text-pragma-muted uppercase tracking-wider px-1">
        <div className="col-span-5">{t("quoteDescription")}</div>
        <div className="col-span-2">Qty</div>
        <div className="col-span-2">Price</div>
        <div className="col-span-2">Total</div>
        <div className="col-span-1" />
      </div>

      {items.map((item, index) => (
        <div
          key={item.id}
          className="grid grid-cols-1 sm:grid-cols-12 gap-3 items-start bg-pragma-bg/50 rounded-lg p-3"
        >
          <div className="sm:col-span-5">
            <input
              type="text"
              value={item.description}
              onChange={(e) => updateItem(item.id, "description", e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter" && index === items.length - 1) {
                  e.preventDefault();
                  addItem();
                }
              }}
              placeholder="Description..."
              className="w-full bg-pragma-surface border border-pragma-border rounded-lg px-3 py-2 text-sm text-pragma-text placeholder:text-pragma-muted/50 focus:outline-none focus:border-pragma-accent/50"
            />
          </div>
          <div className="sm:col-span-2">
            <label className="block sm:hidden text-xs text-pragma-muted mb-1">Qty</label>
            <input
              type="number"
              min="1"
              value={item.quantity}
              onChange={(e) => updateItem(item.id, "quantity", parseInt(e.target.value) || 0)}
              className="w-full bg-pragma-surface border border-pragma-border rounded-lg px-3 py-2 text-sm text-pragma-text focus:outline-none focus:border-pragma-accent/50"
            />
          </div>
          <div className="sm:col-span-2">
            <label className="block sm:hidden text-xs text-pragma-muted mb-1">Unit price</label>
            <input
              type="number"
              min="0"
              step="0.01"
              value={item.unitPrice}
              onChange={(e) => updateItem(item.id, "unitPrice", parseFloat(e.target.value) || 0)}
              className="w-full bg-pragma-surface border border-pragma-border rounded-lg px-3 py-2 text-sm text-pragma-text focus:outline-none focus:border-pragma-accent/50"
            />
          </div>
          <div className="sm:col-span-2 flex items-center text-sm text-pragma-muted py-2">
            {formatCurrency(calculateLineItemTotal(item), currency, locale)}
          </div>
          <div className="sm:col-span-1 flex items-center">
            {items.length > 1 && (
              <button
                type="button"
                onClick={() => removeItem(item.id)}
                className="text-pragma-muted hover:text-red-400 transition-colors cursor-pointer"
              >
                <X size={16} />
              </button>
            )}
          </div>
        </div>
      ))}

      <Button type="button" variant="ghost" size="sm" onClick={addItem}>
        <Plus size={14} />
        {t("addLineItem")}
      </Button>

      {/* Totals */}
      <div className="border-t border-pragma-border pt-4">
        <div className="flex items-center gap-4 mb-4">
          <label className="text-sm text-pragma-muted">{t("discountLabel")}</label>
          <input
            type="number"
            min="0"
            max="100"
            value={discount}
            onChange={(e) => updateData({ discount: parseFloat(e.target.value) || 0 })}
            className="w-20 bg-pragma-surface border border-pragma-border rounded-lg px-3 py-1.5 text-sm text-pragma-text focus:outline-none focus:border-pragma-accent/50"
          />
        </div>
        <div className="flex flex-col gap-1 text-sm">
          <div className="flex justify-between gap-4">
            <span className="text-pragma-muted">Subtotal:</span>
            <span>{formatCurrency(subtotal, currency, locale)}</span>
          </div>
          {discount > 0 && (
            <div className="flex justify-between gap-4">
              <span className="text-pragma-muted">Discount ({discount}%):</span>
              <span className="text-red-400">
                -{formatCurrency(subtotal * (discount / 100), currency, locale)}
              </span>
            </div>
          )}
          <div className="flex justify-between gap-4 text-lg font-bold border-t border-pragma-accent/30 pt-2 mt-1">
            <span>Total:</span>
            <span className="text-pragma-accent">
              {formatCurrency(total, currency, locale)}
            </span>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { Button } from "@/shared/components/ui/Button";
import { Plus, X } from "lucide-react";
import { nanoid } from "nanoid";
import type { DeliverablesBlock, QuoteBlock, Deliverable } from "../../types";

interface Props {
  block: DeliverablesBlock;
  onUpdate: (block: QuoteBlock) => void;
}

export function DeliverablesBlockEditor({ block, onUpdate }: Props) {
  const t = useTranslations("Admin");
  const { items } = block.data;

  function updateItems(newItems: Deliverable[]) {
    onUpdate({ ...block, data: { items: newItems } });
  }

  function addDeliverable() {
    updateItems([
      ...items,
      { id: nanoid(6), number: items.length + 1, title: "", description: "" },
    ]);
  }

  function removeDeliverable(id: string) {
    const filtered = items.filter((d) => d.id !== id);
    updateItems(filtered.map((d, i) => ({ ...d, number: i + 1 })));
  }

  function updateDeliverable(id: string, field: keyof Deliverable, value: string | number) {
    updateItems(items.map((d) => (d.id === id ? { ...d, [field]: value } : d)));
  }

  return (
    <div className="space-y-3">
      {items.map((d) => (
        <div key={d.id} className="bg-pragma-bg/50 rounded-lg p-3 space-y-2">
          <div className="flex items-center gap-3">
            <span className="text-pragma-accent font-bold text-lg w-6 shrink-0">
              {d.number}
            </span>
            <input
              type="text"
              value={d.title}
              onChange={(e) => updateDeliverable(d.id, "title", e.target.value)}
              placeholder={t("deliverableTitle")}
              className="flex-1 bg-pragma-surface border border-pragma-border rounded-lg px-3 py-2 text-sm text-pragma-text placeholder:text-pragma-muted/50 focus:outline-none focus:border-pragma-accent/50"
            />
            <button
              type="button"
              onClick={() => removeDeliverable(d.id)}
              className="text-pragma-muted hover:text-red-400 transition-colors cursor-pointer"
            >
              <X size={16} />
            </button>
          </div>
          <div className="pl-9">
            <input
              type="text"
              value={d.description}
              onChange={(e) => updateDeliverable(d.id, "description", e.target.value)}
              placeholder={t("deliverableDesc")}
              className="w-full bg-pragma-surface border border-pragma-border rounded-lg px-3 py-2 text-sm text-pragma-text placeholder:text-pragma-muted/50 focus:outline-none focus:border-pragma-accent/50"
            />
          </div>
        </div>
      ))}
      <Button type="button" variant="ghost" size="sm" onClick={addDeliverable}>
        <Plus size={14} />
        {t("addDeliverable")}
      </Button>
    </div>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { Input } from "@/shared/components/ui/Input";
import type { PricingBlock, QuoteBlock } from "../../types";

interface Props {
  block: PricingBlock;
  onUpdate: (block: QuoteBlock) => void;
}

export function PricingBlockEditor({ block, onUpdate }: Props) {
  const t = useTranslations("Admin");

  function updateData(patch: Partial<PricingBlock["data"]>) {
    onUpdate({ ...block, data: { ...block.data, ...patch } });
  }

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <Input
          id={`${block.blockId}-timeline`}
          label={t("timeline")}
          value={block.data.timeline || ""}
          onChange={(e) => updateData({ timeline: e.target.value })}
          placeholder="e.g. 3 semanas"
        />
        <Input
          id={`${block.blockId}-fixedPrice`}
          type="number"
          label={t("fixedPrice")}
          value={block.data.fixedPrice.toString()}
          onChange={(e) => updateData({ fixedPrice: parseFloat(e.target.value) || 0 })}
          placeholder="35000"
        />
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <Input
          id={`${block.blockId}-listPrice`}
          type="number"
          label={t("listPrice")}
          value={block.data.listPrice?.toString() || ""}
          onChange={(e) => updateData({ listPrice: e.target.value ? parseFloat(e.target.value) : undefined })}
          placeholder="60000"
        />
        <Input
          id={`${block.blockId}-preferentialNote`}
          label={t("preferentialNote")}
          value={block.data.preferentialNote || ""}
          onChange={(e) => updateData({ preferentialNote: e.target.value })}
          placeholder="Por tratarse de..."
        />
      </div>
      <Input
        id={`${block.blockId}-paymentTerms`}
        label={t("paymentTerms")}
        value={block.data.paymentTerms || ""}
        onChange={(e) => updateData({ paymentTerms: e.target.value })}
        placeholder="50% al arranque, 50% a la entrega"
      />
    </div>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { Button } from "@/shared/components/ui/Button";
import { Plus, X } from "lucide-react";
import type { NextStepsBlock, QuoteBlock } from "../../types";

interface Props {
  block: NextStepsBlock;
  onUpdate: (block: QuoteBlock) => void;
}

export function NextStepsBlockEditor({ block, onUpdate }: Props) {
  const t = useTranslations("Admin");
  const { steps } = block.data;

  function updateSteps(newSteps: string[]) {
    onUpdate({ ...block, data: { steps: newSteps } });
  }

  return (
    <div className="space-y-2">
      {steps.map((step, i) => (
        <div key={i} className="flex items-center gap-3">
          <span className="text-pragma-muted text-sm w-5 shrink-0">{i + 1}.</span>
          <input
            type="text"
            value={step}
            onChange={(e) =>
              updateSteps(steps.map((s, idx) => (idx === i ? e.target.value : s)))
            }
            placeholder={`${t("nextStep")} ${i + 1}...`}
            className="flex-1 bg-pragma-surface border border-pragma-border rounded-lg px-3 py-2 text-sm text-pragma-text placeholder:text-pragma-muted/50 focus:outline-none focus:border-pragma-accent/50"
          />
          <button
            type="button"
            onClick={() => updateSteps(steps.filter((_, idx) => idx !== i))}
            className="text-pragma-muted hover:text-red-400 transition-colors cursor-pointer"
          >
            <X size={16} />
          </button>
        </div>
      ))}
      <Button
        type="button"
        variant="ghost"
        size="sm"
        onClick={() => updateSteps([...steps, ""])}
      >
        <Plus size={14} />
        {t("addNextStep")}
      </Button>
    </div>
  );
}

