"use client";

import { useState, useRef } from "react";
import { useTranslations, useLocale } from "next-intl";
import { useRouter } from "@/i18n/navigation";
import { Button } from "@/shared/components/ui/Button";
import { Input } from "@/shared/components/ui/Input";
import { Select } from "@/shared/components/ui/Select";
import { Card } from "@/shared/components/ui/Card";
import { useToast } from "@/shared/components/ui/Toaster";
import { createQuoteAction, updateQuoteAction } from "../actions";
import type { Quote, QuoteBlock, BlockType, Currency } from "../types";
import { CURRENCY_LABELS, BLOCK_REGISTRY } from "../types";
import { nanoid } from "nanoid";
import { Save, Link2, Eye } from "lucide-react";
import { BlockEditor } from "./blocks/BlockEditor";
import { AddBlockMenu } from "./blocks/AddBlockMenu";

interface QuoteFormProps {
  quote?: Quote;
}

type FieldErrors = Record<string, string[] | undefined>;

export function QuoteForm({ quote }: QuoteFormProps) {
  const t = useTranslations("Admin");
  const locale = useLocale();
  const router = useRouter();
  const { toast } = useToast();
  const formRef = useRef<HTMLFormElement>(null);

  const [currency, setCurrency] = useState<Currency>(quote?.currency || "MXN");
  const [blocks, setBlocks] = useState<QuoteBlock[]>(quote?.blocks || []);
  const [fieldErrors, setFieldErrors] = useState<FieldErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  // ─── Block handlers ──────────────────────────────────────────────────────

  function addBlock(type: BlockType) {
    const config = BLOCK_REGISTRY[type];
    const newBlock: QuoteBlock = {
      blockId: nanoid(8),
      type,
      order: blocks.length,
      data: config.createDefault(),
    } as QuoteBlock;
    setBlocks((prev) => [...prev, newBlock]);
  }

  function updateBlock(blockId: string, updated: QuoteBlock) {
    setBlocks((prev) => prev.map((b) => (b.blockId === blockId ? updated : b)));
  }

  function removeBlock(blockId: string) {
    setBlocks((prev) =>
      prev.filter((b) => b.blockId !== blockId).map((b, i) => ({ ...b, order: i }))
    );
  }

  function moveBlock(blockId: string, direction: -1 | 1) {
    setBlocks((prev) => {
      const idx = prev.findIndex((b) => b.blockId === blockId);
      if (idx < 0) return prev;
      const newIdx = idx + direction;
      if (newIdx < 0 || newIdx >= prev.length) return prev;
      const copy = [...prev];
      [copy[idx], copy[newIdx]] = [copy[newIdx], copy[idx]];
      return copy.map((b, i) => ({ ...b, order: i }));
    });
  }

  // ─── Form submission ─────────────────────────────────────────────────────

  function buildFormData(base: FormData, status: string): FormData {
    base.set("currency", currency);
    base.set("status", status);
    base.set("blocks", JSON.stringify(blocks));
    return base;
  }

  async function handleSubmit(formData: FormData, status: string) {
    setIsSubmitting(true);
    setFieldErrors({});
    buildFormData(formData, status);

    if (quote) {
      const result = await updateQuoteAction(quote.id, formData);
      setIsSubmitting(false);
      if ("error" in result) {
        setFieldErrors(result.error as FieldErrors);
        toast("Please fix the errors below", "error");
        return;
      }
      toast("Quote saved", "success");
      router.push("/admin");
    } else {
      const result = await createQuoteAction(formData);
      setIsSubmitting(false);
      if ("error" in result) {
        setFieldErrors(result.error as FieldErrors);
        toast("Please fix the errors below", "error");
        return;
      }

      if (status === "sent" && result.id) {
        const baseUrl = window.location.origin;
        await navigator.clipboard.writeText(
          `${baseUrl}/${locale}/quote/${result.id}`
        );
        toast("Link copied to clipboard!", "success");
        setTimeout(() => router.push("/admin"), 1500);
      } else {
        toast("Quote saved as draft", "success");
        router.push("/admin");
      }
    }
  }

  async function handlePreview() {
    if (!formRef.current) return;
    const formData = buildFormData(new FormData(formRef.current), "draft");

    if (quote) {
      window.open(`/${locale}/quote/${quote.id}`, "_blank");
      return;
    }

    setIsSubmitting(true);
    setFieldErrors({});
    const result = await createQuoteAction(formData);
    setIsSubmitting(false);

    if ("error" in result) {
      setFieldErrors(result.error as FieldErrors);
      toast("Please fix the errors below", "error");
      return;
    }

    window.open(`/${locale}/quote/${result.id}`, "_blank");
    toast("Draft saved — redirecting to edit", "info");
    router.push(`/admin/quotes/${result.id}/edit`);
  }

  const currencyOptions = Object.entries(CURRENCY_LABELS).map(
    ([value, label]) => ({ value, label })
  );

  return (
    <form
      ref={formRef}
      action={async (formData) => handleSubmit(formData, "draft")}
      className="max-w-4xl mx-auto space-y-6"
    >
      {/* Client Info */}
      <Card>
        <h3 className="text-sm font-semibold text-pragma-muted uppercase tracking-wider mb-4">
          Client Info
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <Input
            id="clientName"
            name="clientName"
            label={t("clientName")}
            defaultValue={quote?.clientName}
            error={fieldErrors.clientName?.[0]}
            required
          />
          <Input
            id="clientEmail"
            name="clientEmail"
            type="email"
            label={t("clientEmail")}
            defaultValue={quote?.clientEmail}
            error={fieldErrors.clientEmail?.[0]}
            required
          />
          <Input
            id="clientCompany"
            name="clientCompany"
            label={t("clientCompany")}
            defaultValue={quote?.clientCompany}
          />
        </div>
      </Card>

      {/* Quote Details */}
      <Card>
        <h3 className="text-sm font-semibold text-pragma-muted uppercase tracking-wider mb-4">
          Quote Details
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <Input
            id="title"
            name="title"
            label={t("quoteTitle")}
            defaultValue={quote?.title}
            error={fieldErrors.title?.[0]}
            required
          />
          <Select
            id="currency"
            label={t("currency")}
            options={currencyOptions}
            value={currency}
            onChange={(e) => setCurrency(e.target.value as Currency)}
          />
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mt-4">
          <Input
            id="validUntil"
            name="validUntil"
            type="date"
            label={t("validUntil")}
            defaultValue={quote?.validUntil}
          />
          <Select
            id="locale"
            name="locale"
            label={t("locale")}
            options={[
              { value: "en", label: "English" },
              { value: "es", label: "Espanol" },
            ]}
            defaultValue={quote?.locale || "en"}
          />
        </div>
      </Card>

      {/* Blocks */}
      {blocks.map((block, index) => (
        <BlockEditor
          key={block.blockId}
          block={block}
          currency={currency}
          locale={locale}
          isFirst={index === 0}
          isLast={index === blocks.length - 1}
          onUpdate={(updated) => updateBlock(block.blockId, updated)}
          onMoveUp={() => moveBlock(block.blockId, -1)}
          onMoveDown={() => moveBlock(block.blockId, 1)}
          onRemove={() => removeBlock(block.blockId)}
        />
      ))}

      {/* Add Block */}
      <AddBlockMenu existingBlocks={blocks} onAdd={addBlock} />

      {fieldErrors.blocks && (
        <p className="text-sm text-red-400">{fieldErrors.blocks[0]}</p>
      )}

      {/* Actions */}
      <div className="flex flex-col sm:flex-row justify-end gap-3">
        <Button
          type="button"
          variant="ghost"
          size="md"
          disabled={isSubmitting}
          onClick={handlePreview}
        >
          <Eye size={16} />
          {t("preview")}
        </Button>
        <Button
          type="submit"
          variant="secondary"
          size="md"
          disabled={isSubmitting}
        >
          <Save size={16} />
          {t("saveAsDraft")}
        </Button>
        <Button
          type="button"
          variant="primary"
          size="md"
          disabled={isSubmitting}
          onClick={async () => {
            if (!formRef.current) return;
            const formData = new FormData(formRef.current);
            await handleSubmit(formData, "sent");
          }}
        >
          <Link2 size={16} />
          {t("saveAndShare")}
        </Button>
      </div>
    </form>
  );
}

import type { QuoteBlock, Currency } from "../../types";
