import { useTranslations } from "next-intl";
import { Card } from "@/shared/components/ui/Card";
import type { LineItemsBlock, Currency } from "../../types";
import {
  formatCurrency,
  calculateLineItemTotal,
  calculateSubtotal,
  calculateTotal,
} from "../../types";

interface Props {
  block: LineItemsBlock;
  currency: Currency;
  locale: string;
}

export function LineItemsBlockViewer({ block, currency, locale }: Props) {
  const t = useTranslations("Quote");
  const { items, discount, heading } = block.data;
  if (items.length === 0) return null;

  const subtotal = calculateSubtotal(items);
  const discountAmount = subtotal * (discount / 100);
  const total = calculateTotal(items, discount);

  return (
    <Card className="overflow-hidden">
      {heading && (
        <h3 className="text-xs font-semibold text-pragma-muted uppercase tracking-wider mb-4">
          {heading}
        </h3>
      )}

      {/* Desktop table */}
      <div className="hidden sm:block">
        <table className="w-full">
          <thead>
            <tr className="border-b border-pragma-border">
              <th className="pb-3 text-left text-xs font-medium text-pragma-muted uppercase tracking-wider">
                {t("description")}
              </th>
              <th className="pb-3 text-right text-xs font-medium text-pragma-muted uppercase tracking-wider">
                {t("qty")}
              </th>
              <th className="pb-3 text-right text-xs font-medium text-pragma-muted uppercase tracking-wider">
                {t("unitPrice")}
              </th>
              <th className="pb-3 text-right text-xs font-medium text-pragma-muted uppercase tracking-wider">
                {t("total")}
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-pragma-border/30">
            {items.map((item) => (
              <tr key={item.id}>
                <td className="py-3 text-sm">{item.description}</td>
                <td className="py-3 text-sm text-right text-pragma-muted">{item.quantity}</td>
                <td className="py-3 text-sm text-right text-pragma-muted">
                  {formatCurrency(item.unitPrice, currency, locale)}
                </td>
                <td className="py-3 text-sm text-right">
                  {formatCurrency(calculateLineItemTotal(item), currency, locale)}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Mobile cards */}
      <div className="sm:hidden space-y-4">
        {items.map((item) => (
          <div key={item.id} className="bg-pragma-bg/50 rounded-lg p-4">
            <p className="font-medium text-sm">{item.description}</p>
            <div className="flex justify-between mt-2 text-sm text-pragma-muted">
              <span>
                {item.quantity} x {formatCurrency(item.unitPrice, currency, locale)}
              </span>
              <span className="text-pragma-text">
                {formatCurrency(calculateLineItemTotal(item), currency, locale)}
              </span>
            </div>
          </div>
        ))}
      </div>

      {/* Totals */}
      <div className="border-t border-pragma-border mt-4 pt-4">
        <div className="flex flex-col gap-1 text-sm">
          <div className="flex justify-between gap-4">
            <span className="text-pragma-muted">{t("subtotal")}:</span>
            <span>{formatCurrency(subtotal, currency, locale)}</span>
          </div>
          {discount > 0 && (
            <div className="flex justify-between gap-4">
              <span className="text-pragma-muted">
                {t("discount")} ({discount}%):
              </span>
              <span className="text-red-400">
                -{formatCurrency(discountAmount, currency, locale)}
              </span>
            </div>
          )}
          <div className="flex justify-between gap-4 text-xl font-bold mt-2 px-4 py-3 rounded-lg border border-pragma-accent/30 shadow-[0_0_15px_rgba(0,240,255,0.12)]">
            <span>{t("total")}:</span>
            <span className="text-pragma-accent">
              {formatCurrency(total, currency, locale)}
            </span>
          </div>
        </div>
      </div>
    </Card>
  );
}

