function TableBlockPdf({ block }: { block: TableBlock }) {
  const { heading, columns, rows, highlightLastRow } = block.data;
  if (columns.length === 0) return null;

  const colWidth = `${100 / columns.length}%`;

  return (
    <View style={{ marginBottom: 16 }}>
      {heading ? <Text style={styles.groupHeading}>{heading}</Text> : null}
      <View style={styles.tableHeader}>
        {columns.map((col, i) => (
          <Text key={i} style={[styles.tableHeaderText, { width: colWidth }]}>{col}</Text>
        ))}
      </View>
      {rows.map((row, ri) => {
        const isLast = ri === rows.length - 1;
        const highlight = highlightLastRow && isLast;
        return (
          <View
            key={ri}
            style={[
              styles.tableRow,
              highlight ? { borderTopWidth: 2, borderTopColor: colors.accent } : {},
            ]}
          >
            {row.map((cell, ci) => (
              <Text
                key={ci}
                style={[
                  { width: colWidth, fontSize: 10, color: "#333" },
                  highlight ? { fontFamily: "Helvetica-Bold" } : {},
                ]}
              >
                {cell}
              </Text>
            ))}
          </View>
        );
      })}
    </View>
  );
}

